const body = $input.first().json;
const { username, passwordHash, userId, profile } = body;

if (!username || !passwordHash || !userId) {
  return [{ json: { ok: false, error: 'Missing required fields' } }];
}

const staticData = $getWorkflowStaticData('global');
if (!staticData.users) staticData.users = {};

if (staticData.users[username]) {
  return [{ json: { ok: false, error: 'Username already taken' } }];
}

staticData.users[username] = { passwordHash, userId, profile };

return [{ json: { ok: true, userId } }];

const body = $input.first().json;
const { username, passwordHash } = body;

if (!username || !passwordHash) {
  return [{ json: { ok: false, error: 'Missing credentials' } }];
}

const staticData = $getWorkflowStaticData('global');
const users = staticData.users || {};
const user = users[username];

if (!user) {
  return [{ json: { ok: false, error: 'User not found' } }];
}

if (user.passwordHash !== passwordHash) {
  return [{ json: { ok: false, error: 'Invalid password' } }];
}

return [{ json: { ok: true, userId: user.userId, profile: user.profile } }];

const body = $input.first().json;
const { username, profile } = body;

if (!username || !profile) {
  return [{ json: { ok: false, error: 'Missing fields' } }];
}

const staticData = $getWorkflowStaticData('global');
if (!staticData.users || !staticData.users[username]) {
  return [{ json: { ok: false, error: 'User not found' } }];
}

staticData.users[username].profile = profile;

return [{ json: { ok: true } }];
